	 * @param disp The calling dispatcher
	 * @param cmd the IBallCmd passed to the dispatcher.
	 */
    @Override
	public void update(IDispatcher<IBallCmd> disp, IBallCmd cmd) { 
    	cmd.apply(this, disp);
    };


